<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { Refresh, Search } from '@element-plus/icons-vue'
import { ElMessage, ElMessageBox } from 'element-plus'

import { getRiderDetail, getRiders, riderAction } from '@/api/adminConsole'
import PageHeader from '@/components/PageHeader.vue'
import { useAuthStore } from '@/stores/auth'
import type { RiderQuery, RiderRow } from '@/types/admin'

const auth = useAuthStore(); const rows = ref<RiderRow[]>([]); const total = ref(0); const loading = ref(false)
const detail = ref<RiderRow | null>(null); const drawer = ref(false)
const filters = reactive({ keyword: '', auditStatus: '', riderStatus: '' }); const page = reactive({ pageNum: 1, pageSize: 20 })
function query(): RiderQuery { const q: RiderQuery={...page}; if(filters.keyword.trim())q.keyword=filters.keyword.trim(); if(filters.auditStatus!=='')q.auditStatus=Number(filters.auditStatus); if(filters.riderStatus!=='')q.riderStatus=Number(filters.riderStatus); return q }
async function load():Promise<void>{loading.value=true;try{const r=await getRiders(query());rows.value=r.records;total.value=r.total}finally{loading.value=false}}
function search():void{page.pageNum=1;void load()}
async function open(value:unknown):Promise<void>{const row=value as RiderRow;detail.value=await getRiderDetail(row.riderId);drawer.value=true}
async function action(type:'approve'|'reject'|'enable'|'disable'):Promise<void>{if(!detail.value)return;let reason:string|undefined;if(type==='reject'||type==='disable'){const r=await ElMessageBox.prompt('请输入原因，结果会同步到骑手端','操作原因',{inputPattern:/^.{2,255}$/,inputErrorMessage:'请输入2至255个字符'});reason=r.value}else{await ElMessageBox.confirm(`确认执行${type==='approve'?'审核通过':'启用'}？`,'操作确认')}await riderAction(detail.value.riderId,type,reason);ElMessage.success('操作成功');detail.value=await getRiderDetail(detail.value.riderId);await load()}
onMounted(()=>void load())
</script>
<template><div class="page-shell"><PageHeader title="骑手中心" subtitle="审核与账号状态变更实时影响骑手端接单权限"><template #actions><el-button :icon="Refresh" :loading="loading" @click="load">刷新</el-button></template></PageHeader><section class="content-panel"><el-form class="filter-grid"><el-form-item label="关键词"><el-input v-model="filters.keyword" clearable placeholder="姓名、昵称、手机号" @keyup.enter="search" /></el-form-item><el-form-item label="审核状态"><el-select v-model="filters.auditStatus" clearable><el-option label="全部" value=""/><el-option label="审核中" :value="0"/><el-option label="已通过" :value="1"/><el-option label="已拒绝" :value="2"/></el-select></el-form-item><el-form-item label="骑手状态"><el-select v-model="filters.riderStatus" clearable><el-option label="全部" value=""/><el-option label="未开通" :value="0"/><el-option label="正常" :value="1"/><el-option label="已禁用" :value="2"/></el-select></el-form-item><div class="filter-actions"><el-button type="primary" :icon="Search" @click="search">查询</el-button><el-button @click="Object.assign(filters,{keyword:'',auditStatus:'',riderStatus:''});search()">重置</el-button></div></el-form></section><section class="content-panel table-panel"><el-table v-loading="loading" :data="rows" border><el-table-column prop="riderId" label="骑手ID" width="90"/><el-table-column prop="realName" label="姓名" min-width="120"/><el-table-column prop="phone" label="手机号" width="140"/><el-table-column label="审核状态" width="110"><template #default="{row}"><el-tag :type="row.auditStatus===1?'success':row.auditStatus===2?'danger':'warning'">{{row.auditStatusText}}</el-tag></template></el-table-column><el-table-column label="账号状态" width="100"><template #default="{row}"><el-tag :type="row.riderStatus===1?'success':row.riderStatus===2?'danger':'info'">{{row.riderStatusText}}</el-tag></template></el-table-column><el-table-column prop="deliveryCount" label="配送数" width="90"/><el-table-column prop="completedCount" label="完成数" width="90"/><el-table-column label="完成率" width="100"><template #default="{row}">{{Number(row.completionRate).toFixed(2)}}%</template></el-table-column><el-table-column prop="createTime" label="申请时间" min-width="170"/><el-table-column label="操作" width="90" fixed="right"><template #default="{row}"><el-button link type="primary" @click="open(row)">详情</el-button></template></el-table-column></el-table><div class="pagination-bar"><el-pagination v-model:current-page="page.pageNum" v-model:page-size="page.pageSize" :total="total" :page-sizes="[20,50,100]" layout="total, sizes, prev, pager, next" @current-change="load" @size-change="search"/></div></section><el-drawer v-model="drawer" title="骑手详情" size="620px"><template v-if="detail"><el-descriptions :column="2" border><el-descriptions-item label="姓名">{{detail.realName}}</el-descriptions-item><el-descriptions-item label="手机号">{{detail.phone||'-'}}</el-descriptions-item><el-descriptions-item label="身份证">{{detail.idCard}}</el-descriptions-item><el-descriptions-item label="完成率">{{Number(detail.completionRate).toFixed(2)}}%</el-descriptions-item><el-descriptions-item label="审核状态">{{detail.auditStatusText}}</el-descriptions-item><el-descriptions-item label="账号状态">{{detail.riderStatusText}}</el-descriptions-item><el-descriptions-item label="原因" :span="2">{{detail.rejectReason||'-'}}</el-descriptions-item></el-descriptions><div class="documents"><el-image :src="detail.idCardFront" fit="cover"><template #error><div class="image-error">身份证正面不可用</div></template></el-image><el-image :src="detail.idCardBack" fit="cover"><template #error><div class="image-error">身份证反面不可用</div></template></el-image></div><div class="drawer-actions"><el-button v-if="detail.auditStatus===0&&auth.hasPermission('rider:audit')" type="success" @click="action('approve')">审核通过</el-button><el-button v-if="detail.auditStatus===0&&auth.hasPermission('rider:audit')" type="danger" plain @click="action('reject')">审核拒绝</el-button><el-button v-if="detail.auditStatus===1&&detail.riderStatus===2&&auth.hasPermission('rider:manage')" type="success" @click="action('enable')">启用</el-button><el-button v-if="detail.auditStatus===1&&detail.riderStatus===1&&auth.hasPermission('rider:manage')" type="danger" plain @click="action('disable')">禁用</el-button><el-button disabled>配送收入（预留）</el-button><el-button disabled>当前位置（预留）</el-button></div></template></el-drawer></div></template>
<style scoped>.documents{display:grid;margin-top:18px;grid-template-columns:1fr 1fr;gap:12px}.documents .el-image{height:180px;border:1px solid #e1e6ed;border-radius:6px}.image-error{display:grid;height:100%;color:#909399;background:#f5f7fa;place-items:center}.drawer-actions{display:flex;margin-top:18px;flex-wrap:wrap;gap:10px}</style>
